   122→    this.providerBreakdown[provBucket] += tokens;
   123→
   124→    // Check if budget is now exhausted
   125→    if (!this.budgetExhausted && this.tokensUsed >= this.dailyBudget) {
   126→      this.budgetExhausted = true;
