   134→    }
   135→  }
   136→
   137→  /**
   138→   * Check if OpenAI should be skipped due to budget exhaustion.
   139→   * @returns {boolean} true if OpenAI budget is exhausted
   140→   */
   141→  isOpenAIBudgetExhausted() {
   142→    // Check if day rolled over
   143→    const today = this._getUTCDay();
   144→    if (today !== this.currentDay) {
